@Test
public void booleanAttributeOutputEmptyString() {
    Document doc = Jsoup.parse("<input disabled='' readonly='' checked='checked'>");
    Element input = doc.selectFirst("input");
    assertEquals("<input disabled readonly checked>", input.outerHtml());
}

@Test
public void booleanAttributeOutputNonBooleanAttribute() {
    Document doc = Jsoup.parse("<div data-flag='' class='test'>");
    Element div = doc.selectFirst("div");
    assertEquals("<div data-flag=\"\" class=\"test\"></div>", div.outerHtml());
}

@Test
public void booleanAttributeOutputXmlSyntax() {
    Document doc = Jsoup.parse("<input checked='' disabled='disabled'>");
    doc.outputSettings().syntax(Document.OutputSettings.Syntax.xml);
    Element input = doc.selectFirst("input");
    assertEquals("<input checked=\"\" disabled=\"disabled\" />", input.outerHtml());
}
